alter table public.consulta_vet_medications
  add column if not exists official_site_url text,
  add column if not exists leaflet_url text,
  add column if not exists image_url text;

insert into public.consulta_vet_categories (slug, title, description, sort_order, is_published)
values (
  'infectologia',
  'Infectologia',
  'Doenças infecciosas, antimicrobianos e stewardship em pequenos animais.',
  10,
  true
)
on conflict (slug) do update
set
  title = excluded.title,
  description = excluded.description,
  is_published = true,
  updated_at = now();

