insert into public.consulta_vet_medications (
  category_id,
  slug,
  title,
  active_ingredient,
  trade_names,
  pharmacologic_class,
  species,
  tags,
  mechanism_of_action,
  indications,
  contraindications,
  cautions,
  adverse_effects,
  interactions,
  routes,
  doses,
  presentations,
  clinical_notes_rich_text,
  admin_notes_text,
  "references",
  official_site_url,
  leaflet_url,
  image_url,
  is_published
)
select
  category.id,
  records.slug,
  records.title,
  records.active_ingredient,
  array(select jsonb_array_elements_text(records.trade_names)),
  records.pharmacologic_class,
  array(select jsonb_array_elements_text(records.species)),
  array(select jsonb_array_elements_text(records.tags)),
  records.mechanism_of_action,
  array(select jsonb_array_elements_text(records.indications)),
  array(select jsonb_array_elements_text(records.contraindications)),
  array(select jsonb_array_elements_text(records.cautions)),
  array(select jsonb_array_elements_text(records.adverse_effects)),
  array(select jsonb_array_elements_text(records.interactions)),
  array(select jsonb_array_elements_text(records.routes)),
  records.doses,
  records.presentations,
  records.clinical_notes_rich_text,
  'Seed editorial de antibióticos comerciais BR importado da pesquisa textual de 24/06/2026. Produtos incompletos do documento não foram importados automaticamente.',
  records."references",
  records.official_site_url,
  records.leaflet_url,
  records.image_url,
  true
from records
cross join category
on conflict (slug) do update
set
  category_id = excluded.category_id,
  title = excluded.title,
  active_ingredient = excluded.active_ingredient,
  trade_names = excluded.trade_names,
  pharmacologic_class = excluded.pharmacologic_class,
  species = excluded.species,
  tags = excluded.tags,
  mechanism_of_action = excluded.mechanism_of_action,
  indications = excluded.indications,
  contraindications = excluded.contraindications,
  cautions = excluded.cautions,
  adverse_effects = excluded.adverse_effects,
  interactions = excluded.interactions,
  routes = excluded.routes,
  doses = excluded.doses,
  presentations = excluded.presentations,
  clinical_notes_rich_text = excluded.clinical_notes_rich_text,
  admin_notes_text = excluded.admin_notes_text,
  "references" = excluded."references",
  official_site_url = excluded.official_site_url,
  leaflet_url = excluded.leaflet_url,
  image_url = excluded.image_url,
  is_published = true,
  updated_at = now();
